const body = $json.body ?? $json;
const question = String(body.question ?? '').trim();
if (!question) {
  throw new Error('question is required');
}

const pathname = String(body.pathname ?? '/').trim() || '/';
const rawHistory = Array.isArray(body.history) ? body.history : [];
const history = rawHistory
  .slice(-8)
  .map((entry) => ({
    role: entry?.role === 'user' ? 'user' : 'assistant',
    text: String(entry?.text ?? '').trim().slice(0, 700),
  }))
  .filter((entry) => entry.text);

return [{
  json: {
    question: question.slice(0, 1200),
    pathname: pathname.slice(0, 255),
    history,
    user: body.user ?? null,
    source: body.source ?? 'pwise-dev-overlay',
    requested_at: body.requested_at ?? new Date().toISOString(),
  },
}];

const question = String($json.question || '').trim();
const pathname = String($json.pathname || '/').trim() || '/';
const history = Array.isArray($json.history)
  ? $json.history
  : JSON.parse(String($json.history || '[]'));
const context = typeof $json.context === 'string' ? JSON.parse($json.context) : ($json.context || {});

const recentHistory = history.length
  ? history.map((entry) => `${entry.role}: ${entry.text}`).join('\n')
  : 'No prior chat history.';

const contextJson = JSON.stringify(context, null, 2);

const systemPrompt = [
  'You are Wise Assistant for the pwise web app.',
  'Answer questions about layout, navigation, screen purpose, control location, and what the user should click or do.',
  'Use the provided app context as the source of truth.',
  'When the user asks where something is, describe the screen and visual location in plain UI terms.',
  'When the user asks how to do something, give short actionable steps.',
  'If the answer is not grounded in the provided context, say that the current assistant context does not include it.',
  'Do not invent routes, buttons, or settings that are not in the context.',
  'Keep answers concise and practical.',
].join(' ');

const userPrompt = [
  `Current route: ${pathname}`,
  `User question: ${question}`,
  'Recent chat history:',
  recentHistory,
  'App context JSON:',
  contextJson,
].join('\n\n');

return [{
  json: {
    question,
    pathname,
    systemPrompt,
    userPrompt,
  },
}];

const answer = String($json.output ?? '').trim();
if (!answer) {
  throw new Error('DeepSeek did not return an assistant answer');
}

return [{
  json: {
    answer,
    source: 'n8n',
    model: 'deepseek-chat',
  },
}];
